sql:
SELECT rain_mm, min_temp, max_temp, min_humidity, max_humidity, min_wind_speed, max_wind_speed, cloud_cover, solar_radiation, atmospheric_pressure, data_source
FROM weather_data
WHERE record_id = 0 AND rain_mm > 5;

external_knowledge:
- Frequent instances in this context mean more than 5 occurrences;
- Critical weather irregularities refer to high-severity anomalies;
- Areas are defined by district IDs in the database.

sql:
SELECT d.district_name
FROM districts d
INNER JOIN district_climate_zones dc ON d.district_id = dc.district_id;

SELECT trend_id, avg_annual_temp, avg_annual_humidity, data_source
FROM long_term_trends
WHERE district_id = 0;

SELECT MAX(predicted_rain_mm) AS max_rainfall
FROM forecasts
WHERE district_id = 0;

SELECT mandal_name
FROM mandals
WHERE district_id = 101;

SELECT DISTINCT users.user_name 
FROM users 
INNER JOIN access_logs ON users.user_id = access_logs.user_id;

SELECT (COUNT(*) * 100.0 / (SELECT COUNT(*) FROM weather_data)) AS anomaly_percentage
FROM weather_anomalies
WHERE detected_by = 'Alice Smith';

SELECT COUNT(DISTINCT wd.district_id) AS num_districts
FROM weather_anomalies wa
JOIN weather_data wd ON wa.record_id = wd.record_id;

SELECT w.record_id, w.date, w.district_id, d.district_name
FROM weather_data w
INNER JOIN districts d ON w.district_id = d.district_id;
